import re

def detect_cascade_errors(response):
    tool_blocks = re.findall(r'tool_use.*?tool_use', response.content[0].text, re.DOTALL)
    for i, block in enumerate(tool_blocks):
        if 'error' in block.lower() and i < len(tool_blocks)-1:
            next_block = tool_blocks[i+1]
            if re.search(r'parse|invalid|none', next_block.lower()):
                return {'type': 'cascade_error', 'position': i}
    return None

def detect_parallel_conflicts(tools):
    conflicts = []
    prices = {}
    inventory = {}
    for tool in tools:
        if tool.name == 'get_price':
            prices[tool.input.get('product_id')] = tool.output
        elif tool.name == 'check_inventory':
            inventory[tool.input.get('product_id')] = tool.output

    for pid in set(prices.keys()) & set(inventory.keys()):
        if prices[pid] > 0 and inventory[pid] == 0:
            conflicts.append({'product': pid, 'conflict': 'out_of_stock'})
    return conflicts

def detect_thought_action_divergence(messages):
    for i, msg in enumerate(messages):
        if msg.role == 'user' and i > 0:
            prev_thinking = messages[i-1].content
            if 'avoid clicking' in prev_thinking[0].text.lower():
                current_tools = msg.content
                if any('click' in tool.text for tool in current_tools if tool.type == 'tool_use'):
                    return {'divergence': 'reasoning_action_mismatch'}
    return None

