import anthropic

client = anthropic.Anthropic()

def safe_tool_chain(messages, tools):
    for tool in tools:
        response = client.messages.create(
            model="claude-3-5-sonnet-20240620",
            max_tokens=1024,
            messages=messages,
            tools=[tool]
        )
        if 'error' in response.content[0].text.lower():
            return {'error': 'tool_failed', 'tool': tool.name}
        messages.append(response)
    return messages

def reconcile_parallel_tools(response):
    tool_results = []
    for content in response.content:
        if content.type == 'tool_result':
            tool_results.append(content)

    # Resolve conflicts before final action
    if len(tool_results) > 1:
        reconciled = merge_tool_results(tool_results)
        response.content.append({
            'type': 'tool_result',
            'tool_use_id': 'reconciled',
            'content': reconciled
        })
    return response

def gated_tool_execution(messages):
    thinking_msg = messages[-1]
    confirmation = client.messages.create(
        model="claude-3-5-sonnet-20240620",
        max_tokens=100,
        system="Confirm this action matches your reasoning. Only say 'confirmed' or explain:",
        messages=[thinking_msg]
    )

    if 'confirmed' not in confirmation.content[0].text.lower():
        return {'blocked': 'action_not_confirmed'}
    return confirmation
